// users/users.service.ts
import { Injectable, UnauthorizedException } from '@nestjs/common';
import * as bcrypt from 'bcrypt';

async updateProfile(userId: number, updateProfileDto: UpdateProfileDto): Promise<User> {
  const user = await this.usersRepository.findOne({ where: { id: userId } });
  if (!user) {
    throw new NotFoundException('Utilisateur non trouvé');
  }

  // Vérification du mot de passe actuel si une modification est demandée
  const hasSensitiveChange = updateProfileDto.newPassword || 
                              updateProfileDto.email || 
                              updateProfileDto.phone;

  if (hasSensitiveChange && updateProfileDto.currentPassword) {
    const isPasswordValid = await bcrypt.compare(updateProfileDto.currentPassword, user.password);
    if (!isPasswordValid) {
      throw new UnauthorizedException('Mot de passe actuel incorrect');
    }
  } else if (hasSensitiveChange && !updateProfileDto.currentPassword) {
    throw new UnauthorizedException('Le mot de passe actuel est requis pour cette modification');
  }

  // Mise à jour des champs
  if (updateProfileDto.firstName) user.firstName = updateProfileDto.firstName;
  if (updateProfileDto.lastName) user.lastName = updateProfileDto.lastName;
  if (updateProfileDto.phone) user.phone = updateProfileDto.phone;
  if (updateProfileDto.newPassword) {
    user.password = await bcrypt.hash(updateProfileDto.newPassword, 10);
  }

  return this.usersRepository.save(user);
}
