// common/validators/is-unique-email.validator.ts
import { Injectable } from '@nestjs/common';
import { ValidatorConstraint, ValidatorConstraintInterface, ValidationArguments } from 'class-validator';
import { UsersService } from '../../users/users.service';

@Injectable()
@ValidatorConstraint({ name: 'IsUniqueEmail', async: true })
export class IsUniqueEmailValidator implements ValidatorConstraintInterface {
  constructor(private usersService: UsersService) {}

  async validate(email: string, args: ValidationArguments): Promise<boolean> {
    const userId = (args.object as any).id; // Pour les mises à jour
    const user = await this.usersService.findByEmail(email);
    if (!user) return true;
    // Si c'est une mise à jour et que l'utilisateur trouvé est le même, c'est valide
    if (userId && user.id === userId) return true;
    return false;
  }

  defaultMessage(args: ValidationArguments): string {
    return 'Cet email est déjà utilisé';
  }
}

// Utilisation dans un DTO
export class CreateUserDto {
  @IsEmail()
  @Validate(IsUniqueEmailValidator)
  email: string;
}
